args.sparql:
SELECT ?city_label
WHERE {
  ?event wdt:P1001 wd:Q1708938;
         wdt:P1001 ?X.
  FILTER(?X != wd:Q1708938).

  ?event2 wdt:P1001 ?X;
          wdt:P1001 wd:Q1162702;
          wdt:P1159 wd:Q1162702.

  ?event3 wdt:P1001 ?X;
          wdt:P1001 wd:Q20815716;
          wdt:P1159 wd:Q20815716.

  ?event wdt:P585 ?date.
  ?event wdt:P131 ?city.
  ?city rdfs:label ?city_label.
}
ORDER BY ASC(?date)
LIMIT 1

SELECT ?city_label
WHERE {
  wd:Q1708938 wdt:P735 ?x .
  wd:Q1162702 wdt:P735 ?x .
  wd:Q20815716 wdt:P735 ?x .

  {
    wd:Q1708938 wdt:P735 ?x ;
                wdt:P2326 ?event ;
                wdt:P585 ?date .
    ?event wdt:P131 ?city .
  }
  UNION
  {
    wd:Q1162702 wdt:P735 ?x ;
                wdt:P2326 ?event ;
                wdt:P585 ?date .
    ?event wdt:P131 ?city .
  }
  UNION
  {
    wd:Q20815716 wdt:P735 ?x ;
                wdt:P2326 ?event ;
                wdt:P585 ?date .
    ?event wdt:P131 ?city .
  }
}
ORDER BY ASC(?date)
LIMIT 1

SELECT DISTINCT ?city_label
WHERE {
  ?eventC wdt:P1346 wd:Q1708938 ;
          wdt:P1001 wd:Q1708938 ;
          wdt:P1001 ?X .
  ?eventD wdt:P1346 wd:Q1162702 ;
          wdt:P1001 wd:Q1162702 ;
          wdt:P1001 ?X .
  ?eventS wdt:P1346 wd:Q20815716 ;
          wdt:P1001 wd:Q20815716 ;
          wdt:P1001 ?X .

  { ?eventC wdt:P585 ?date ; wdt:P131 ?city }
  UNION
  { ?eventD wdt:P585 ?date ; wdt:P131 ?city }
  UNION
  { ?eventS wdt:P585 ?date ; wdt:P131 ?city }

  ?city rdfs:label ?city_label
}
ORDER BY ?date
LIMIT 1

SELECT ?city_label
WHERE {
  ?x wdt:P2861 ?m1, ?m2, ?m3 .
  ?m1 wdt:P2860 wd:Q1162702 .
  ?m2 wdt:P2860 wd:Q20815716 .
  ?m3 wdt:P2860 wd:Q1708938 .

  ?m1 wdt:P585 ?d1 ; wdt:P131 ?city .
  ?m2 wdt:P585 ?d2 ; wdt:P131 ?city .
  ?m3 wdt:P585 ?d3 ; wdt:P131 ?city .

  { SELECT ?city ?date
    WHERE {
      ?m1 wdt:P585 ?date ; wdt:P131 ?city .
    }
    UNION
    {
      ?m2 wdt:P585 ?date ; wdt:P131 ?city .
    }
    UNION
    {
      ?m3 wdt:P585 ?date ; wdt:P131 ?city .
    }
    ORDER BY ASC(?date)
    LIMIT 1
  }

  ?city rdfs:label ?city_label
}
LIMIT 1

